var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"근무 시간 내내 사무실 공기에 날이 서 있다.","JPN":"勤務時間中、事務室の雰囲気はピリピリしている。","ENG":"The workplace atmosphere is on edge throughout the day.","TWN":"上班時間辦公室內總是充斥著緊張的氣氛。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"이봐요, 출근 시간 딱 맞춰서 회사를 나오면 어떡합니까?","JPN":"君～、始業時間ピッタリに出勤してどうするんだ？","ENG":"Hey, who comes into the office at exactly 9 o'clock, huh?","TWN":"我說你，哪有人幾點上班就真的幾點到公司的？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"경력이 쌓였으면 모범을 보여야지. 회사가 놀러다니는 곳이야?","JPN":"キャリアを積んだら手本を示してくれないと。会社は遊び場じゃないんだぞ。","ENG":"You've been here long enough to set an example to others. Do you think this is a place where you can come and go as you please?","TWN":"你在公司的時間也不短，要有點榜樣吧？公司是玩樂的地方嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"아니, 누가 차 끌고 다니랬어요?","JPN":"誰も車出勤を強要してないだろう？","ENG":"Hey, it's not my fault you brought your car to work.","TWN":"拜託，是有人逼你開車上班嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"변명은 됐고 이따 나랑 얘기 좀 해요. 지금은 내가 좀 바빠서.","JPN":"言い訳はいいから後でちょっと来たまえ。今は忙しいから。","ENG":"Enough with the excuses. We'll talk more about it  later. I'm busy right now.","TWN":"少在那邊找藉口，待會兒跟我談一下，我現在有點忙。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"아끼던 골프채가 부서졌나? 아침부터 아내와 다퉜나?","JPN":"大事にしていたゴルフクラブが折れたのか？　それとも朝から奥さんとケンカしたのか？","ENG":"Did his precious golf club break? Or did he have a fight with his wife this morning?","TWN":"心愛的高爾夫球桿斷掉嗎？一早就和太太吵架嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"상사가 예민한 날에는 항상 구실이 있다. 나와 아무런 관계도 없고, 내가 어찌할 수도 없는 구실이.","JPN":"上司がイラ立っている日にはいつも口実がある。僕とはなんの関係もなく、僕がどうすることもできない口実が。","ENG":"There's always some type of rant on days when he's not in a good mood. It has nothing to do with me, but there's nothing I can do about it as well.","TWN":"主管在尷尬的時刻總是會有藉口，那些和我一點關係也沒有，我也無可奈何的藉口。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"칸막이를 친 책상이 묫자리처럼 을씨년스럽다.","JPN":"パーティションに囲まれた席が墓場のようにうすら寒い。","ENG":"Man, sitting inside this cubicle makes me feel like I'm suffocating...","TWN":"設有隔板的辦公桌就像墳墓般淒涼。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"의, 의장님! 언제 오셨어요?","JPN":"ぎ、議長！　いついらっしゃったのですか？","ENG":"M-Mr. Chairman! You've arrived early!","TWN":"議…議長！您是什麼時候來的？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"미리 말씀이라도 해 주시지. 그럼 저희가 편안히 모셨을 텐데요.","JPN":"事前におっしゃってくだされば、私たちがちゃんとお迎えしましたのに。","ENG":"You should've called, then I would've sent a car for you.","TWN":"怎麼沒先說一聲呢？這樣我們才好接待您的嘛。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"하하, 사업으로 바쁠 텐데 유난 떨 것 없지.","JPN":"はは、事業で忙しいだろう、無駄な気遣いは不要だ。","ENG":"Haha. I'm sure you're busy, running this place and all.","TWN":"呵呵，你們應該都忙著在做生意吧，無需格外對我費心。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"헤이븐은 어디 있나?","JPN":"ヘイブンはどこだ？","ENG":"Speaking of, where is Haven?","TWN":"天堂呢？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 님은…… 지금 부재 중이셔요.","JPN":"ヘイブン様は……ただいま留守にしております。","ENG":"Mr. Haven is... busy right now.","TWN":"天堂先生……目前不在。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"흠. 아쉽게 됐군. 그럼 이야기는 다음 기회로 미뤄야겠어.","JPN":"ふむ。残念だな。それでは話はまた今度にしよう。","ENG":"Hmm... That's a shame. Then perhaps I should come another day.","TWN":"嗯，真可惜，那就下次再談囉。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아앗! 의장님. 잠시, 잠시만요!","JPN":"ああっ！　議長。ちょっと、ちょっとお待ちを！","ENG":"Oh! Mr. Chairman, please wait!","TWN":"那個！議長，請先稍等一下！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"음? 뭔가?","JPN":"うむ？　何だ？","ENG":"Hmm? What is it?","TWN":"嗯？什麼事？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"여기까지 오셨는데 저희에게 대접할 기회는 주셔야죠.","JPN":"ここまでご足労くださったのですから、おもてなしをするチャンスくらいはください。","ENG":"But you came all this way. Please allow me to at least make it up to you.","TWN":"您大駕光臨，總得給我們個機會招待您吧。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};